// package-lock.json generation script
const fs = require('fs');
const path = require('path');
const execSync = require('child_process').execSync;

function generateLockFile() {
  const cwd = process.cwd();
  const lockFilePath = path.join(cwd, 'package-lock.json');
  const packageJsonPath = path.join(cwd, 'package.json');

  // Read the package.json file
  const packageJson = JSON.parse(fs.readFileSync(packageJsonPath));

  // Generate a lock file for each package
  const packages = Object.keys(packageJson.dependencies);
  packages.forEach((packageName) => {
    const packageLockFilePath = path.join(cwd, 'node_modules', packageName, 'package-lock.json');
    if (fs.existsSync(packageLockFilePath)) {
      const packageLockJson = JSON.parse(fs.readFileSync(packageLockFilePath));
      fs.writeFileSync(lockFilePath, JSON.stringify(packageLockJson, null, 2));
    } else {
      execSync(`npm install --save-exact ${packageName}`, { cwd: cwd });
    }
  });
}

// Example usage of the function
const lockFilePath = path.join(__dirname, 'package-lock.json');
generateLockFile(lockFilePath);